      index = c(0.25, 0.5, 0.75),
      estimate = c(1, 2, 3),
      lower = c(0.5, 1.5, 2.5),
      upper = c(1.5, 2.5, 3.5)
    )
  )
  p <- .plot_quantile_pred(pred)
  expect_s3_class(p, "gg")
})

